module design_325(
    input clk,
    input rst_n,
    output [7:0] data_out
);
    // 设计实现: 可配置步长
    reg [7:0] counter;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            counter <= 0;
        else
            counter <= counter + 1;
    end

    assign data_out = counter;
endmodule

